CREATE TABLE IF NOT EXISTS public.gym_daily_plans (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE, plan_date DATE NOT NULL, workout_plan JSONB, meal_plan JSONB DEFAULT '[]'::jsonb, daily_tip TEXT, target_calories INTEGER DEFAULT 2500, target_macros JSONB DEFAULT '{"protein": 150, "carbs": 300, "fat": 70}'::jsonb, is_rest_day BOOLEAN NOT NULL DEFAULT false, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE(user_id, plan_date))